import{_ as a,v as t,f as o,i as r}from"./chunks/framework.jfF5glnW.js";const _=JSON.parse('{"title":"Week 11 | 铸砂铸造实践","description":"","frontmatter":{"title":"Week 11 | 铸砂铸造实践","date":"2026-05-12T00:00:00.000Z","tags":["课程周志","铸砂铸造","工艺实践"],"cover":"/code2real_blog/posts/week11/67.jpg"},"headers":[],"relativePath":"posts/week11.md","filePath":"posts/week11.md"}'),s={name:"posts/week11.md"};function l(p,e,i,c,d,g){return t(),o("div",null,[...e[0]||(e[0]=[r('<p>第十一周进入铸砂铸造实践。本周的重点是理解砂型制作、浇注通道和成型质量之间的关系。</p><hr><img src="/code2real_blog/posts/week11/67.jpg" alt="Week 11 image"><h2 id="本周学习内容" tabindex="-1">本周学习内容 <a class="header-anchor" href="#本周学习内容" aria-label="Permalink to &quot;本周学习内容&quot;">​</a></h2><p>本周学习铸砂铸造的基本流程，包括模型准备、砂型填充、压实、开模、设置浇道和冒口，以及后续浇注成型的基本原理。与前几周的电子设计不同，铸造更强调材料、形状和工艺条件之间的配合。</p><p>砂型并不是简单把模型埋进砂里。砂的紧实程度、分型面位置、浇口设计和排气路径都会影响最终成品。如果某一步处理粗糙，后面浇注时就可能出现缺料、气孔或表面质量差等问题。</p><h2 id="实践过程" tabindex="-1">实践过程 <a class="header-anchor" href="#实践过程" aria-label="Permalink to &quot;实践过程&quot;">​</a></h2><p>实践中先观察铸造模型的外形，判断分型方向和可能的脱模位置。随后将型砂逐层填入砂箱并压实，保证模型周围砂型有足够支撑力。开模时需要控制力度，避免破坏已经形成的型腔。</p><p>完成型腔后，再处理浇道和排气位置。这个步骤看起来简单，但实际决定了金属液能否顺利进入型腔。浇道过窄会影响流动，排气不足则容易形成气孔，因此不能只关注模型本身。</p><h2 id="遇到的问题" tabindex="-1">遇到的问题 <a class="header-anchor" href="#遇到的问题" aria-label="Permalink to &quot;遇到的问题&quot;">​</a></h2><p>本周最主要的问题是砂型稳定性。压实不足时，开模后边缘容易松散；压得过重或操作不均匀，又可能导致局部变形。砂型质量不稳定，后续浇注结果就很难保证。</p><p>另一个问题是对浇注路径的理解不够直观。一开始容易把浇道当作一个简单入口，但实际还要考虑金属液流动方向、填充顺序和空气排出。铸造过程不像软件建模那样可随时回退，前期判断很重要。</p><h2 id="本周收获" tabindex="-1">本周收获 <a class="header-anchor" href="#本周收获" aria-label="Permalink to &quot;本周收获&quot;">​</a></h2><p>第十一周让我认识到传统制造工艺中的经验含量。铸砂铸造看似流程固定，但每一步都需要根据模型结构进行判断。</p><p>这次实践也补充了我对“实体制造”的理解。无论是 3D 打印还是铸造，模型最终都要接受材料和工艺限制的检验。设计时如果忽略制造过程，结果很可能在实际成型阶段暴露问题。</p><img src="/code2real_blog/posts/week11/1.jpg" alt="Week 11 image"><img src="/code2real_blog/posts/week11/2.jpg" alt="Week 11 image"><img src="/code2real_blog/posts/week11/3.jpg" alt="Week 11 image"><img src="/code2real_blog/posts/week11/4.jpg" alt="Week 11 image"><img src="/code2real_blog/posts/week11/5.jpg" alt="Week 11 image">',20)])])}const k=a(s,[["render",l]]);export{_ as __pageData,k as default};
